/* ─────────────────────────────────────────────────────────────
   COUNT-UP HOOK
───────────────────────────────────────────────────────────── */
const useCountUp = (target, duration = 1200) => {
  const rawNum = parseFloat(String(target).replace(/[^0-9.]/g, '')) || 0;
  const [val, setVal] = useState(0);
  const prev = useRef(0);
  useEffect(() => {
    const from = prev.current;
    prev.current = rawNum;
    if (rawNum === 0) { setVal(0); return; }
    let start = null;
    const step = (ts) => {
      if (!start) start = ts;
      const p = Math.min((ts - start) / duration, 1);
      const eased = 1 - Math.pow(1 - p, 3);
      setVal(Math.round(from + eased * (rawNum - from)) / 1);
      if (p < 1) requestAnimationFrame(step);
      else setVal(rawNum);
    };
    requestAnimationFrame(step);
  }, [rawNum]);
  return val;
};

