/* ─────────────────────────────────────────────────────────────
   KPI CARD
───────────────────────────────────────────────────────────── */
const KPICard = ({ title, value, unit = '', prefix = '', change, icon: Icon, color = '#00D4FF' }) => {
  const num = parseFloat(String(value).replace(/[^0-9.]/g, '')) || 0;
  const counted = useCountUp(num);
  const isLarge = num >= 1000;
  const display = prefix + (isLarge ? Math.round(counted).toLocaleString('en-IN') : counted.toFixed(num < 10 ? 2 : 1)) + (unit ? ` ${unit}` : '');
  return (
    <GCard glow={color} style={{ cursor: 'default', transition: 'border-color .2s' }}
      onMouseEnter={e => e.currentTarget.style.borderColor = `${color}44`}
      onMouseLeave={e => e.currentTarget.style.borderColor = 'rgba(255,255,255,0.07)'}
    >
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 14 }}>
        <span style={{ fontFamily: 'Space Mono', fontSize: 8, color: 'rgba(255,255,255,0.3)', letterSpacing: 2, textTransform: 'uppercase' }}>{title}</span>
        {Icon && <Icon size={13} color={color} style={{ opacity: 0.6 }} />}
      </div>
      <div style={{ fontFamily: 'Space Mono', fontWeight: 700, fontSize: 24, color: '#fff', lineHeight: 1 }}>
        {display}
      </div>
      {change != null && (
        <div style={{ display: 'flex', alignItems: 'center', gap: 4, marginTop: 10 }}>
          {change >= 0 ? <TrendingUp size={10} color="#00FF88" /> : <TrendingDown size={10} color="#FF3366" />}
          <span style={{ fontFamily: 'Space Mono', fontSize: 9, color: change >= 0 ? '#00FF88' : '#FF3366' }}>
            {change >= 0 ? '+' : ''}{change}%
          </span>
        </div>
      )}
    </GCard>
  );
};

/* ─────────────────────────────────────────────────────────────
   DATA JOIN — aggregate by Platform+Date, join Raw+AF
───────────────────────────────────────────────────────────── */
const joinData = (rawRows) => {
  const dump = rawRows.filter(r => r.Source === 'Raw Dump');
  const af   = rawRows.filter(r => r.Source === 'AppsFlyer');

  const aggDump = {};
  dump.forEach(r => {
    const k = `${r.Platform}|||${r.Date}`;
    if (!aggDump[k]) aggDump[k] = { Platform: r.Platform, Date: r.Date, Spends: 0, Impressions: 0, Clicks: 0, Views: 0 };
    aggDump[k].Spends      += Number(r.Spends) || 0;
    aggDump[k].Impressions += Number(r.Impressions) || 0;
    aggDump[k].Clicks      += Number(r.Clicks) || 0;
    aggDump[k].Views       += Number(r.Views) || 0;
  });

  const aggAF = {};
  af.forEach(r => {
    const k = `${r.Platform}|||${r.Date}`;
    if (!aggAF[k]) aggAF[k] = { Platform: r.Platform, Date: r.Date, Installs: 0, Sessions: 0, Add_to_Cart: 0, First_Order: 0, Purchase: 0 };
    aggAF[k].Installs    += Number(r.Installs) || 0;
    aggAF[k].Sessions    += Number(r.Sessions) || 0;
    aggAF[k].Add_to_Cart += Number(r.Add_to_Cart) || 0;
    aggAF[k].First_Order += Number(r.First_Order) || 0;
    aggAF[k].Purchase    += Number(r.Purchase) || 0;
  });

  const allKeys = new Set([...Object.keys(aggDump), ...Object.keys(aggAF)]);

  return Array.from(allKeys).map(k => {
    const d = aggDump[k], a = aggAF[k];
    const imp    = d?.Impressions || 0;
    const spends = d?.Spends || 0;
    const clicks = d?.Clicks || 0;
    const views  = d?.Views  || 0;
    const sess  = a?.Sessions || 0;
    const inst   = a?.Installs || 0;
    return {
      Platform:    (d || a).Platform,
      Date:        (d || a).Date,
      Spends:      spends,
      Impressions: imp,
      Clicks:      clicks,
      Views:       views,
      CTR:   imp > 0 ? +((clicks / imp) * 100).toFixed(3) : 0,
      VTR:   imp > 0 ? +((views  / imp) * 100).toFixed(3) : 0,
      CPM:   imp > 0 ? +((spends / imp) * 1000).toFixed(2) : 0,
      CPI:   inst > 0 ? +(spends / inst).toFixed(2) : 0,
      CPS:   sess > 0 ? +(spends / sess).toFixed(2) : 0,
      Installs:    inst,
      Sessions:    sess,
      Add_to_Cart: a?.Add_to_Cart || 0,
      First_Order: a?.First_Order || 0,
      Purchase:    a?.Purchase || 0,
      status: d && a ? 'matched' : d ? 'raw_only' : 'af_only',
    };
  }).sort((a, b) => new Date(a.Date) - new Date(b.Date));
};

